export default function PublicPricingPage() {
  usePageTitle('Pricing');
  const [annual, setAnnual] = useState(false)
  const [openFaq, setOpenFaq] = useState(null)
  const mobile = useIsMobile()
  const [promoCode, setPromoCode] = useState('')
  const [promoResult, setPromoResult] = useState(null)
  const [promoLoading, setPromoLoading] = useState(false)
  const [tiers, setTiers] = useState(FALLBACK_TIERS)
  const [addOns, setAddOns] = useState(FALLBACK_ADDONS)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    fetch(`${getApiBase()}/pricing`)
      .then(r => r.json())
      .then(data => {
        if (data?.tiers?.length > 0) setTiers(data.tiers)
        if (data?.add_ons?.length > 0) setAddOns(data.add_ons)
      })
      .catch(() => {})
      .finally(() => setLoading(false))
  }, [])

  useEffect(() => {
    const params = new URLSearchParams(window.location.search)
    const code = params.get('promo') || params.get('code')
    if (code) {
      setPromoCode(code.toUpperCase())
      fetch(`${getApiBase()}/billing/discount/validate`, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ code: code.toUpperCase() }),
      }).then(r => r.json()).then(d => setPromoResult(d)).catch(() => {})
    }
  }, [])

  const handleValidatePromo = () => {
    if (!promoCode.trim()) return
    setPromoLoading(true)
    fetch(`${getApiBase()}/billing/discount/validate`, {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ code: promoCode.trim().toUpperCase() }),
    })
      .then(r => r.json())
      .then(d => { setPromoResult(d); setPromoLoading(false) })
      .catch(() => { setPromoResult({ valid: false, error: 'Network error' }); setPromoLoading(false) })
  }

  const getColor = (tier) => TIER_COLORS[tier.id] || T.textSecondary
  const isPopular = (tier) => tier.id === 'pro'
  const annualSavings = (tier) => {
    const monthly = tier.price_usd || 0
    const annualMonthly = tier.annual_price_usd || monthly
    return (monthly * 12) - (annualMonthly * 12)
  }
  const formatLimit = (val) => {
    if (val === 'unlimited') return 'Unlimited'
    if (Array.isArray(val)) return val.join(', ').toUpperCase()
    if (val === 'all') return 'All 14'
    if (val === true) return 'Yes'
    if (val === false) return 'No'
    return String(val ?? '-')
  }

  return (
    <div className={s.page}>
      <PublicNav />

      {/* Hero */}
      <section className={`${s.hero} ${mobile ? s.heroMobile : ''}`}>
        <div className={s.logoWrap}><AuraLogo variant="icon" height={64} glow /></div>
        <h1 className={s.heroTitle}>Simple, Transparent Pricing</h1>
        <p className={s.heroSubtitle}>Start free. Scale when you're ready. No hidden fees.</p>
        <div className={s.toggleWrap}>
          <span className={`${s.toggleLabel} ${!annual ? s.toggleLabelActive : s.toggleLabelInactive}`}>Monthly</span>
          <button onClick={() => setAnnual(!annual)} className={`${s.toggleTrack} ${annual ? s.toggleTrackOn : s.toggleTrackOff}`}>
            <span className={`${s.toggleKnob} ${annual ? s.toggleKnobOn : s.toggleKnobOff}`} />
          </button>
          <span className={`${s.toggleLabel} ${annual ? s.toggleLabelActive : s.toggleLabelInactive}`}>
            Annual <span className={s.saveBadge}>Save up to 35%</span>
          </span>
        </div>
      </section>

      {/* Promo */}
      <section className={`${s.promoSection} ${mobile ? s.promoSectionMobile : ''}`}>
        <div className={`${s.promoCard} ${mobile ? s.promoCardMobile : ''}`}>
          <div className={s.promoTitle}>Intro Pricing Available</div>
          <div className={s.promoDesc}>Enter your promo code for a discount on your first 3 months</div>
          <div className={s.promoInputRow}>
            <input type="text" value={promoCode}
              onChange={e => { setPromoCode(e.target.value.toUpperCase()); setPromoResult(null); }}
              placeholder="Enter promo code"
              onKeyDown={e => { if (e.key === 'Enter') handleValidatePromo(); }}
              className={s.promoInput} />
            <button onClick={handleValidatePromo} disabled={promoLoading || !promoCode.trim()}
              className={s.promoApplyBtn}
              style={{ cursor: promoLoading ? 'wait' : 'pointer', opacity: promoLoading || !promoCode.trim() ? 0.5 : 1 }}>
              {promoLoading ? '...' : 'Apply'}
            </button>
          </div>
          {promoResult && (
            <div className={s.promoResult} style={{ color: promoResult.valid ? T.green : T.red }}>
              {promoResult.valid ? promoResult.savings_text : (promoResult.error || 'Invalid code')}
            </div>
          )}
        </div>
      </section>

      {loading && <div className={s.loading}><div className={s.loadingText}>Loading pricing...</div></div>}

      {/* Platform Tiers */}
      <section className={`${s.tierSection} ${mobile ? s.tierSectionMobile : ''}`}>
        <div className={`${s.tierGrid} ${mobile ? s.tierGridMobile : ''}`}>
          {tiers.map((tier) => {
            const color = getColor(tier), popular = isPopular(tier)
            const monthly = tier.price_usd || 0, annualMonthly = tier.annual_price_usd || monthly
            const savings = annualSavings(tier), displayPrice = annual ? annualMonthly : monthly
            const isFree = monthly === 0
            return (
              <div key={tier.id} className={s.tierCard}
                style={{ border: `1px solid ${popular ? color + '55' : T.border}` }}>
                {popular && <div className={s.popularBadge} style={{ background: color }}>MOST POPULAR</div>}
                {tier.bestForLearning && !popular && <div className={s.popularBadge} style={{ background: T.green }}>BEST FOR LEARNING</div>}
                <div className={s.tierName} style={{ color }}>{tier.name}</div>
                <div className={s.tierPriceWrap}>
                  <span className={s.tierPrice}>${displayPrice}</span>
                  <span className={s.tierPriceSuffix}>{isFree ? '' : '/mo'}</span>
                </div>
                {annual && savings > 0 && <div className={s.tierSavings}>Save ${savings.toLocaleString()}/yr</div>}
                {annual && !isFree && <div className={s.tierBilled}>Billed ${(annualMonthly * 12).toLocaleString()}/yr</div>}
                {!annual && !isFree && <div className={s.tierSpacer} />}
                {isFree && <div className={s.tierFreeLabel}>Free forever</div>}
                <Link to={isFree ? '/register' : '/billing'} className={s.tierCtaBtn} style={{
                  background: popular ? `linear-gradient(135deg, ${T.blue}, ${T.purple})` : T.surface2,
                  border: popular ? 'none' : `1px solid ${T.border}`,
                }}>{isFree ? 'Start Free' : 'Get Started'}</Link>
                {tier.limits && (
                  <div style={{ marginBottom: 12 }}>
                    {tier.limits.bots != null && <div className={s.limitRow}><span className={s.checkIcon}>&#10003;</span>{formatLimit(tier.limits.bots)} bot{tier.limits.bots !== 1 ? 's' : ''}</div>}
                    {tier.limits.strategies != null && <div className={s.limitRow}><span className={s.checkIcon}>&#10003;</span>{formatLimit(tier.limits.strategies)} strategies</div>}
                    {tier.limits.regions != null && <div className={s.limitRow}><span className={s.checkIcon}>&#10003;</span>{formatLimit(tier.limits.regions)} region{tier.limits.regions === 'all' || (Array.isArray(tier.limits.regions) && tier.limits.regions.length > 1) ? 's' : ''}</div>}
                  </div>
                )}
                <ul className={s.featureList}>
                  {(tier.features || []).map((f, j) => (
                    <li key={j} className={s.featureItem}><span className={s.checkIcon}>&#10003;</span>{FEATURE_LABELS[f] || f.replace(/_/g, ' ')}</li>
                  ))}
                </ul>
                {tier.store_price_apple > 0 && <div className={s.storePrice}>App Store: ${tier.store_price_apple}/mo &middot; Google Play: ${tier.store_price_google}/mo</div>}
              </div>
            )
          })}
        </div>
      </section>

      {/* Feature Comparison */}
      <section className={`${s.compSection} ${mobile ? s.compSectionMobile : ''}`}>
        <h2 className={`${s.compTitle} ${mobile ? s.compTitleMobile : ''}`}>Feature Comparison</h2>
        <div className={s.compTableWrap}>
          <div className={s.compTableInner}>
            <div className={s.compHeader} style={{ display: 'grid', gridTemplateColumns: `2fr ${tiers.map(() => '1fr').join(' ')}` }}>
              <span>Feature</span>
              {tiers.map(tier => <span key={tier.id} style={{ textAlign: 'center', color: getColor(tier) }}>{tier.name}</span>)}
            </div>
            <div className={s.compRow} style={{ display: 'grid', gridTemplateColumns: `2fr ${tiers.map(() => '1fr').join(' ')}`, borderBottom: `1px solid ${T.border}44` }}>
              <span className={s.compRowLabel}>Price</span>
              {tiers.map(tier => {
                const price = annual ? (tier.annual_price_usd || 0) : (tier.price_usd || 0)
                return <span key={tier.id} className={s.compCellCenter}>{price === 0 ? 'Free' : `$${price}/mo`}</span>
              })}
            </div>
            {COMPARISON_KEYS.map((row, i) => (
              <div key={row.key} style={{
                display: 'grid', gridTemplateColumns: `2fr ${tiers.map(() => '1fr').join(' ')}`,
                padding: '12px 20px', fontSize: 13,
                borderBottom: i < COMPARISON_KEYS.length - 1 ? `1px solid ${T.border}44` : 'none',
                background: i % 2 === 0 ? 'transparent' : T.bg + '44',
              }}>
                <span className={s.compRowLabelLight}>{row.label}</span>
                {tiers.map(tier => {
                  const val = tier.limits?.[row.key]
                  return <span key={tier.id} className={s.compCellCenterNormal}>{row.format ? row.format(val) : formatLimit(val)}</span>
                })}
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Add-Ons */}
      <section className={`${s.addOnsSection} ${mobile ? s.addOnsSectionMobile : ''}`}>
        <div className={s.addOnsInner}>
          <h2 className={`${s.addOnsTitle} ${mobile ? s.addOnsTitleMobile : ''}`}>Optional Add-Ons</h2>
          <p className={`${s.addOnsSubtitle} ${mobile ? s.addOnsSubtitleMobile : ''}`}>Enhance your platform with additional capabilities.</p>
          <div className={`${s.addOnsGrid} ${mobile ? s.addOnsGridMobile : ''}`}
               style={{ gridTemplateColumns: mobile ? undefined : `repeat(${Math.min(addOns.length, 4)}, 1fr)` }}>
            {addOns.map((addon) => (
              <div key={addon.id} className={`${s.addonCard} ${mobile ? s.addonCardMobile : ''}`}>
                <div>
                  <div className={s.addonName}>{addon.id.replace(/_/g, ' ')}</div>
                  <div className={s.addonDesc}>{addon.description}</div>
                </div>
                <div className={s.addonFooter}>
                  <div className={s.addonPrice}>${addon.price_usd}<span className={s.addonPriceSuffix}>/mo</span></div>
                  <Link to="/billing" className={s.addonAddBtn}>Add</Link>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* FAQ */}
      <section className={`${s.faqSection} ${mobile ? s.faqSectionMobile : ''}`}>
        <div className={s.faqWrap}>
          <h2 className={`${s.faqTitle} ${mobile ? s.faqTitleMobile : ''}`}>Frequently Asked Questions</h2>
          {FAQ.map((faq, i) => (
            <div key={i} className={s.faqItem}>
              <button onClick={() => setOpenFaq(openFaq === i ? null : i)} className={s.faqBtn}>
                <span className={s.faqQuestion}>{faq.q}</span>
                <span className={`${s.faqToggle} ${openFaq === i ? s.faqToggleOpen : ''}`}>+</span>
              </button>
              {openFaq === i && <p className={s.faqAnswer}>{faq.a}</p>}
            </div>
          ))}
        </div>
      </section>

      {/* CTA */}
      <section className={`${s.ctaSection} ${mobile ? s.ctaSectionMobile : ''}`}>
        <h2 className={`${s.ctaTitle} ${mobile ? s.ctaTitleMobile : ''}`}>Ready to Get Started?</h2>
        <p className={s.ctaSubtitle}>Start with the free tier. Upgrade anytime.</p>
        <div className={s.ctaBtns}>
          <Link to="/register" className={s.ctaPrimaryBtn}>Create Free Account</Link>
          <a href="mailto:sales@auraalpha.cc" className={s.ctaSecondaryBtn}>Contact Sales</a>
        </div>
      </section>

      <PublicFooter />
    </div>
  )
}
